public with sharing class ContactRollupService {
    public static Map<Id, Integer> rollupContactsByAccount(Set<Id> accountIds) {
        if (accountIds == null || accountIds.isEmpty()) {
            return new Map<Id, Integer>();
        }
        // Single bulk query — replaces the per-Account inner SOQL.
        Map<Id, Integer> counts = new Map<Id, Integer>();
        for (Account a : [
            SELECT Id, Name, AnnualRevenue
            FROM Account
            WHERE Id IN :accountIds
            WITH USER_MODE
        ]) {
            counts.put(a.Id, 0);
        }
        for (AggregateResult ar : [
            SELECT AccountId, COUNT(Id) cnt
            FROM Contact
            WHERE AccountId IN :accountIds
            WITH USER_MODE
            GROUP BY AccountId
        ]) {
            counts.put((Id) ar.get('AccountId'), (Integer) ar.get('cnt'));
        }
        return counts;
    }
}
